local b = 'ABCDEFGHIJKLMNOPQRSTUVWXYZabcdefghijklmnopqrstuvwxyz0123456789+/'

local function decode(data)
    -- Очистка от всех левых символов, которые ломают Base64
    data = string.gsub(data, '[^'..b..'=]', '')
    return (data:gsub('.', function(x)
        if x == '=' then return '' end
        local r, f = '', (b:find(x) - 1)
        for i = 6, 1, -1 do r = r .. (f % 2^i - f % 2^(i-1) > 0 and '1' or '0') end
        return r
    end):gsub('%d%d%d%d%d%d%d%d', function(x)
        if (#x ~= 8) then return '' end
        local c = 0
        for i = 1, 8 do c = c + (x:sub(i, i) == '1' and 2^(8 - i) or 0) end
        return string.char(c)
    end))
end

-- ВСТАВЛЯЙ СЮДА СВОЙ BASE64
local encoded_script = ""

-- Запуск
local decoded_code = decode(encoded_script)

if decoded_code and #decoded_code > 0 then
    local success, func = pcall(loadstring, decoded_code)
    if success and func then
        func()
    else
        warn("Ошибка: loadstring вернул nil. Твой экзекутор не поддерживает скрипты или Base64 битый.")
    end
else
    warn("Ошибка: Декодированная строка пуста. Проверь свой Base64.")
end
